queries.sparql:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPlant ?child ; p:hasGreenhouse ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Greenhouse } }
  FILTER(?nf = ?total)
}

